# apps/orders/views.py
def order_list(request):
    orders = Order.objects.all()
    rows = []
    for order in orders:
        rows.append({
            "id": order.id,
            "user": order.user.email,                # 1 query each
            "city": order.shipping_address.city,     # 1 query each
            "items": [i.product.name for i in order.items.all()],  # M+1 each
        })
    return JsonResponse({"orders": rows})

# apps/orders/selectors.py
from django.db.models import Prefetch, QuerySet

def get_order_list() -> QuerySet:
    return (
        Order.objects
        .select_related("user", "shipping_address")
        .prefetch_related(
            Prefetch("items", queryset=Item.objects.select_related("product")),
        )
        .order_by("-created_at")
    )

# apps/orders/views.py
def order_list(request):
    orders = get_order_list()
    rows = [
        {
            "id": o.id,
            "user": o.user.email,
            "city": o.shipping_address.city,
            "items": [i.product.name for i in o.items.all()],
        }
        for o in orders
    ]
    return JsonResponse({"orders": rows})

# tests/test_orders.py
def test_order_list_query_count(client, django_assert_num_queries, order_factory):
    [order_factory() for _ in range(20)]
    with django_assert_num_queries(3):
        resp = client.get("/api/orders/")
    assert resp.status_code == 200
